function all_startup_data_table_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('all_startup_data_table');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'company_id' => Request::val('company_id', ''),
		'name_of_the_company' => Request::val('name_of_the_company', ''),
		'business_sector' => Request::val('business_sector', ''),
		'name_of_the_person' => Request::val('name_of_the_person', ''),
		'mobile_number' => Request::val('mobile_number', ''),
		'email_id' => Request::val('email_id', ''),
		'mode_of_incubation' => Request::val('mode_of_incubation', ''),
		'date_of_incubation' => Request::dateComponents('date_of_incubation', ''),
		'shortlisted_for_fund' => Request::val('shortlisted_for_fund', ''),
		'website_link' => Request::val('website_link', ''),
		'company_logo' => Request::fileUpload('company_logo', [
			'maxSize' => 10240000,
			'types' => 'jpg|jpeg|gif|png|webp',
			'noRename' => false,
			'dir' => '',
			'success' => function($name, $selected_id) {
			},
			'failure' => function($selected_id, $fileRemoved) {
				if(!strlen(Request::val('SelectedID'))) return '';

				/* for empty upload fields, when saving a copy of an existing record, copy the original upload field */
				return existing_value('all_startup_data_table', 'company_logo', Request::val('SelectedID'));
			},
		]),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('all_startup_data_table', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		all_startup_data_table_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function all_startup_data_table_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

