function all_startup_data_table_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('all_startup_data_table', $selected_id, 'edit')) return false;

	$data = [
		'company_id' => Request::val('company_id', ''),
		'name_of_the_company' => Request::val('name_of_the_company', ''),
		'business_sector' => Request::val('business_sector', ''),
		'name_of_the_person' => Request::val('name_of_the_person', ''),
		'mobile_number' => Request::val('mobile_number', ''),
		'email_id' => Request::val('email_id', ''),
		'mode_of_incubation' => Request::val('mode_of_incubation', ''),
		'date_of_incubation' => Request::dateComponents('date_of_incubation', ''),
		'shortlisted_for_fund' => Request::val('shortlisted_for_fund', ''),
		'website_link' => Request::val('website_link', ''),
		'company_logo' => Request::fileUpload('company_logo', [
			'maxSize' => 10240000,
			'types' => 'jpg|jpeg|gif|png|webp',
			'noRename' => false,
			'dir' => '',
			'id' => $selected_id,
			'success' => function($name, $selected_id) {
			},
			'removeOnRequest' => true,
			'remove' => function($selected_id) {
				// do nothing: preserve removed files on server.
			},
			'failure' => function($selected_id, $fileRemoved) {
				if($fileRemoved) return '';
				return existing_value('all_startup_data_table', 'company_logo', $selected_id);
			},
		]),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('all_startup_data_table', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: all_startup_data_table_before_update
	if(function_exists('all_startup_data_table_before_update')) {
		$args = ['old_data' => $old_data];
		if(!all_startup_data_table_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'all_startup_data_table',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="all_startup_data_table_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('all_startup_data_table', $data['selectedID'], calculated_fields()['all_startup_data_table']);

	// hook: all_startup_data_table_after_update
	if(function_exists('all_startup_data_table_after_update')) {
		if($row = getRecord('all_startup_data_table', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!all_startup_data_table_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('all_startup_data_table', $selected_id);
}

function all_startup_data_table_form($selectedId = '', $allowUpdate = true, $allowInsert = true, $allowDelete = true, $separateDV = true, $templateDV = '', $templateDVP = '') {
